import{_ as t,o as r,c as e,ae as i}from"./chunks/framework.B9lykYDM.js";const g=JSON.parse('{"title":"二分查找算法概述","description":"","frontmatter":{"title":"二分查找算法概述","icon":"search","date":"2026-04-05T10:00:00.000Z"},"headers":[],"relativePath":"posts/algorithm/binarySearch/index.md","filePath":"posts/algorithm/binarySearch/index.md"}'),l={name:"posts/algorithm/binarySearch/index.md"};function o(n,a,s,h,d,c){return r(),e("div",null,[...a[0]||(a[0]=[i('<h1 id="二分查找算法概述" tabindex="-1">二分查找算法概述 <a class="header-anchor" href="#二分查找算法概述" aria-label="Permalink to &quot;二分查找算法概述&quot;">​</a></h1><p>二分查找（Binary Search）是一种在<strong>有序数组</strong>中高效查找目标值的算法，其核心思想是通过不断将搜索区间减半，快速逼近目标位置。</p><h2 id="适用条件" tabindex="-1">适用条件 <a class="header-anchor" href="#适用条件" aria-label="Permalink to &quot;适用条件&quot;">​</a></h2><ul><li>数据必须<strong>有序</strong>（升序或降序）</li><li>支持随机访问（如数组）</li></ul><h2 id="基本形式" tabindex="-1">基本形式 <a class="header-anchor" href="#基本形式" aria-label="Permalink to &quot;基本形式&quot;">​</a></h2><ul><li><strong>标准二分</strong>：查找是否存在目标值</li><li><strong>左边界二分</strong>：查找第一个 ≥ target 的位置</li><li><strong>右边界二分</strong>：查找最后一个 ≤ target 的位置</li></ul><h2 id="时间复杂度" tabindex="-1">时间复杂度 <a class="header-anchor" href="#时间复杂度" aria-label="Permalink to &quot;时间复杂度&quot;">​</a></h2><ul><li><strong>时间</strong>：O(log n)</li><li><strong>空间</strong>：O(1)（迭代实现）</li></ul><h2 id="扩展应用" tabindex="-1">扩展应用 <a class="header-anchor" href="#扩展应用" aria-label="Permalink to &quot;扩展应用&quot;">​</a></h2><ul><li>在旋转排序数组中查找</li><li>查找峰值元素</li><li>求平方根（数值逼近）</li><li>分割数组以最小化最大值（二分答案）</li></ul><p>二分查找不仅是基础查找算法，更是“二分答案”思想的基石，广泛应用于算法竞赛与工程优化中。</p>',11)])])}const _=t(l,[["render",o]]);export{g as __pageData,_ as default};
